#include <stdio.h>
#define mod 1000000007
int dp[2001][2001];
int main()
{
	 int n,k,i,j,l;
	 scanf("%d%d",&n,&k);

	 memset(dp,0,sizeof(dp));

	 for (i=1;i<=2000;i++)
	 dp[1][i]=1;             // dp[i][j] : length i and last number j

	 for (i=1;i<k;i++)
	 {
	 	 for (j=1;j<=n;j++)
	 	 {
	 	 	 for (l=1;l*j<=n;l++)
	 	 	 dp[i+1][l*j]=(dp[i+1][l*j]%mod+dp[i][j]%mod)%mod;
	 	 }
	 }

	     int sum=0;
	 	 for (j=1;j<=n;j++)
	 	 sum=(sum%mod+dp[k][j]%mod)%mod;


	 printf("%d\n",sum);
	 return 0;
}

