use std::str::FromStr;
use std::io::stdin;

const MOD: u128 = 1000000007;

fn get_vals<T>(count: usize) -> Vec<T> where
    T: FromStr,
    <T as std::str::FromStr>::Err: std::fmt::Debug {
    let mut val = String::new();
    stdin().read_line(&mut val).expect("Failed to read line");
    val.split_whitespace()
        .map(|x|
            x.parse::<T>().expect("Failed to parse value"))
        .take(count).collect()
}

pub fn main() {
    let mut ins = get_vals::<usize>(2);
    let (n, k) = (ins.remove(0), ins.remove(0));
    let mut dp = vec![vec![0 as u128; k]; n];
    for x in dp[0].iter_mut() {
        *x = 1;
    }
    for i in dp.iter_mut() {
        i[0] = 1;
    }
    for i in 1..dp.len() {
        let facs = factor((i as u64) + 1);
        for j in 1..dp[i].len() {
            dp[i][j] = (&facs).into_iter()
                .map(|x| dp[(*x as usize) - 1][j - 1])
                .sum::<u128>() % MOD;
        }
    }
    // for i in &dp {
    //     for j in i {
    //         print!("{0: <10}", *j)
    //     }
    //     println!()
    // }
    let ans: u128 = dp.iter().map(|x| x[k - 1]).sum();
    println!("{}", ans % MOD)
}

pub fn factor(input: u64) -> Vec<u64> {
    let mut vector = vec![];

    let mut i = 1;
    while i * i <= input {
        if input % i == 0 {
            vector.push(i);
            if i != input / i {
                vector.push(input / i);
            }
        }
        i += 1;
    }

    vector
}
